# Base models - interfaces, enums, and abstract base classes using methods instead of properties

enum Status:
    PENDING = 0
    ACTIVE = 1
    INACTIVE = 2

interface IIdentifiable:
    def get_id() -> int

interface INameable:
    def get_name() -> str

@abstract
class Entity(IIdentifiable):
    _id: int

    def __init__(self, id: int):
        self._id = id

    @virtual
    def get_id(self) -> int:
        return self._id

    @abstract
    def get_status(self) -> Status:
        pass

