# Utility structures and helper functions

from models import Status

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    @virtual
    def distance_from_origin(self) -> float:
        return (self.x * self.x + self.y * self.y) ** 0.5

struct Dimension:
    width: float
    height: float

    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height

    property get area(self) -> float:
        return self.width * self.height

def calculate_center(dim: Dimension) -> Point:
    return Point(dim.width / 2.0, dim.height / 2.0)

def status_to_string(s: Status) -> str:
    if s == Status.PENDING:
        return "Pending"
    elif s == Status.ACTIVE:
        return "Active"
    return "Inactive"

