# Service classes using imported types

from models import Entity, Status, IIdentifiable, INameable
from utils import Point, Dimension

@abstract
class LocalEntity(Entity):
    _position: Point

    def __init__(self, id: int, position: Point):
        super().__init__(id)
        self._position = position

    def get_position(self) -> Point:
        return self._position

class User(LocalEntity, INameable):
    _username: str
    _status: Status

    def __init__(self, id: int, username: str, position: Point):
        super().__init__(id, position)
        self._username = username
        self._status = Status.PENDING

    @override
    def get_status(self) -> Status:
        return self._status

    def activate(self) -> None:
        self._status = Status.ACTIVE

    @override
    def get_name(self) -> str:
        return self._username

class Product(LocalEntity, INameable):
    _product_name: str
    _size: Dimension

    def __init__(self, id: int, name: str, position: Point, size: Dimension):
        super().__init__(id, position)
        self._product_name = name
        self._size = size

    @override
    def get_status(self) -> Status:
        return Status.ACTIVE

    @override
    def get_name(self) -> str:
        return self._product_name

    def get_size(self) -> Dimension:
        return self._size

def create_user(id: int, username: str, x: float, y: float) -> User:
    pos: Point = Point(x, y)
    return User(id, username, pos)
